const cfg = $('⚙️ Load Config').item.json;
const input = $('⚡ Entry').item.json;

const tz = cfg.TIMEZONE || 'Asia/Kuala_Lumpur';
const now = new Date();

function nextOccurrence(targetDays, hour, minute=0) {
  const days = targetDays.split(',').map(d => d.trim().toLowerCase());
  const dayMap = {sunday:0,monday:1,tuesday:2,wednesday:3,thursday:4,friday:5,saturday:6};
  const targets = days.map(d => dayMap[d]).filter(d => d !== undefined);
  const d = new Date(now);
  for (let i = 0; i <= 7; i++) {
    const day = new Date(d);
    day.setDate(d.getDate() + i);
    if (targets.includes(day.getDay())) {
      day.setHours(parseInt(hour), minute, 0, 0);
      if (day > now) return day.toISOString();
    }
  }
  const fallback = new Date(now);
  fallback.setDate(fallback.getDate() + 1);
  fallback.setHours(parseInt(hour), 0, 0, 0);
  return fallback.toISOString();
}

function nextWeekday(hour) {
  const d = new Date(now);
  for (let i = 1; i <= 7; i++) {
    const day = new Date(d);
    day.setDate(d.getDate() + i);
    if (day.getDay() >= 1 && day.getDay() <= 5) {
      day.setHours(parseInt(hour), 0, 0, 0);
      return day.toISOString();
    }
  }
  return new Date(now.getTime() + 86400000).toISOString();
}

const fbDays  = cfg.FACEBOOK_POST_DAYS  || 'tuesday,thursday,wednesday';
const fbHour  = cfg.FACEBOOK_POST_HOUR  || 9;
const igHour  = cfg.INSTAGRAM_POST_HOUR || 11;
const pinDays = cfg.PINTEREST_POST_DAYS || 'saturday,sunday';
const pinHour = cfg.PINTEREST_POST_HOUR || 20;
const ttHour  = cfg.TIKTOK_POST_HOUR    || 19;

return [{ json: {
  article_title:   input.article_title   || '',
  article_url:     input.article_url     || '',
  article_excerpt: input.article_excerpt || '',
  featured_image:  input.featured_image  || '',
  focus_keyword:   input.focus_keyword   || '',
  social_content:  input.social_content  || {},
  schedule: {
    facebook:  nextOccurrence(fbDays, fbHour),
    instagram: nextWeekday(igHour),
    pinterest: nextOccurrence(pinDays, pinHour),
    tiktok:    nextWeekday(ttHour)
  }
}}];

const cfg      = $('⚙️ Load Config').item.json;
const sched    = $('📅 Calculate Schedule Times').item.json;
const blotato  = $input.first().json;
const social   = sched.social_content || {};

// Use Blotato remix output if available, fall back to Agent 6 data
const fbCaption  = blotato?.facebook?.text  || social?.facebook?.caption  || sched.article_title;
const igCaption  = blotato?.instagram?.text || social?.instagram?.caption || sched.article_title;
const pinTitle   = blotato?.pinterest?.text || social?.pinterest?.title   || sched.article_title;
const carouselUrl = blotato?.carousel_url   || sched.featured_image || '';

const rows = [
  {
    Platform:        'Facebook',
    Content_Type:    'text_link',
    Caption:         fbCaption + '\n\n' + sched.article_url,
    Media_URL:       sched.featured_image || '',
    Scheduled_Time:  sched.schedule.facebook,
    Status:          'Queued',
    WP_Post_URL:     sched.article_url,
    Blotato_Post_ID: ''
  },
  {
    Platform:        'Instagram',
    Content_Type:    carouselUrl ? 'carousel' : 'image',
    Caption:         igCaption,
    Media_URL:       carouselUrl || sched.featured_image || '',
    Scheduled_Time:  sched.schedule.instagram,
    Status:          'Queued',
    WP_Post_URL:     sched.article_url,
    Blotato_Post_ID: ''
  },
  {
    Platform:        'Pinterest',
    Content_Type:    'pin',
    Caption:         pinTitle,
    Media_URL:       sched.featured_image || '',
    Scheduled_Time:  sched.schedule.pinterest,
    Status:          'Queued',
    WP_Post_URL:     sched.article_url,
    Blotato_Post_ID: ''
  }
];

// TikTok and YT scripts go to script queue tabs, not Social Queue
return rows.map(r => ({ json: r }));

const cfg   = $('⚙️ Load Config').item.json;
const sched = $('📅 Calculate Schedule Times').item.json;

const msg = `📱 <b>Social Queue Updated</b>

📝 Article: <b>${sched.article_title}</b>

✅ 3 posts queued:
• Facebook → ${new Date(sched.schedule.facebook).toLocaleString('en-MY', {timeZone: cfg.TIMEZONE})}
• Instagram → ${new Date(sched.schedule.instagram).toLocaleString('en-MY', {timeZone: cfg.TIMEZONE})}
• Pinterest → ${new Date(sched.schedule.pinterest).toLocaleString('en-MY', {timeZone: cfg.TIMEZONE})}

Posts will auto-publish via Blotato.`;

return [{ json: { telegram_message: msg, chat_id: cfg.TELEGRAM_CHAT_ID } }];
